DECLARE
  i NUMBER := 1;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    i := i + 1;
    EXIT WHEN i > 5;
  END LOOP;
END;

DECLARE
  i NUMBER := 10;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    i := i - 1;
    EXIT WHEN i < 1;
  END LOOP;
END;

DECLARE
  i NUMBER := 1; s NUMBER := 0;
BEGIN
  LOOP
    s := s + i;
    i := i + 1;
    EXIT WHEN i > 10;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Sum: ' || s);
END;

DECLARE
  n NUMBER := 2; i NUMBER := 1;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(n || ' * ' || i || ' = ' || (n*i));
    i := i + 1;
    EXIT WHEN i > 10;
  END LOOP;
END;

DECLARE
  i NUMBER := 2;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    i := i + 2;
    EXIT WHEN i > 20;
  END LOOP;
END;

DECLARE
  i NUMBER := 45;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    i := i + 1;
    EXIT WHEN i > 50;
  END LOOP;
END;

DECLARE
  i NUMBER := 1;
BEGIN
  WHILE i <= 10 LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    i := i + 1;
  END LOOP;
END;

DECLARE
  n NUMBER := 5; f NUMBER := 1;
BEGIN
  WHILE n > 0 LOOP
    f := f * n;
    n := n - 1;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Factorial: ' || f);
END;

DECLARE
  n NUMBER := 123; s NUMBER := 0;
BEGIN
  WHILE n > 0 LOOP
    s := s + MOD(n, 10);
    n := TRUNC(n / 10);
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Sum: ' || s);
END;

DECLARE
  n NUMBER := 123; r NUMBER := 0;
BEGIN
  WHILE n > 0 LOOP
    r := (r * 10) + MOD(n, 10);
    n := TRUNC(n / 10);
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Reversed: ' || r);
END;

DECLARE
  n NUMBER := 121; r NUMBER := 0; temp NUMBER;
BEGIN
  temp := n;
  WHILE n > 0 LOOP
    r := (r * 10) + MOD(n, 10);
    n := TRUNC(n / 10);
  END LOOP;
  IF temp = r THEN DBMS_OUTPUT.PUT_LINE('Palindrome'); END IF;
END;

DECLARE
  a NUMBER:=0; b NUMBER:=1; c NUMBER; i NUMBER:=1;
BEGIN
  WHILE i <= 5 LOOP
    DBMS_OUTPUT.PUT_LINE(a);
    c := a + b; a := b; b := c; i := i + 1;
  END LOOP;
END;

BEGIN
