END;

BEGIN
  FOR i IN REVERSE 1..5 LOOP
    DBMS_OUTPUT.PUT_LINE(i);
  END LOOP;
END;

DECLARE
  s NUMBER := 0;
BEGIN
  FOR i IN 1..10 LOOP s := s + i; END LOOP;
  DBMS_OUTPUT.PUT_LINE(s);
END;

BEGIN
