BEGIN
  FOR i IN 1..20 LOOP
    IF MOD(i, 2) != 0 THEN DBMS_OUTPUT.PUT_LINE(i); END IF;
  END LOOP;
END;

DECLARE
  v_star VARCHAR2(10);
BEGIN
  FOR i IN 1..4 LOOP
    v_star := v_star || '*';
    DBMS_OUTPUT.PUT_LINE(v_star);
  END LOOP;
END;

BEGIN
  FOR i IN 1..3 LOOP
    FOR j IN 1..5 LOOP
      DBMS_OUTPUT.PUT_LINE(i || '*' || j || '=' || (i*j));
    END LOOP;
  END LOOP;
END;

DECLARE
  v_num VARCHAR2(10);
BEGIN
  FOR i IN 1..4 LOOP
    v_num := v_num || i;
    DBMS_OUTPUT.PUT_LINE(v_num);
  END LOOP;
END;

BEGIN
  FOR i IN 1..20 LOOP
    CONTINUE WHEN MOD(i, 4) = 0;
    DBMS_OUTPUT.PUT_LINE(i);
  END LOOP;
END;

DECLARE
  s NUMBER := 0; i NUMBER := 1;
BEGIN
  LOOP
    s := s + i;
    DBMS_OUTPUT.PUT_LINE(i);
    i := i + 1;
    EXIT WHEN s > 100;
  END LOOP;
END;

BEGIN
